      lifecycle: [
        { typeStatus: 'deity', startEvent: 'existence-as-crocodile-river-goddess-of-the-Sobat', era: 'mythic-prehistoric', eraOrdering: 0, sources: [{ kind: 'primary', reference: 'Hofmayr Die Schilluk; Seligman 1911 ethnographic study; David Graeber 2011' }], notes: 'Crocodile-river-goddess; daughter of Dunyel Ju\'Okwa (a half-man-half-crocodile river-being). Half-woman-half-crocodile in form. Resides at the mouth of the Sobat River where it joins the White Nile — the structural center of Shilluk territorial identity.' },
        { typeStatus: 'deity', startEvent: 'capture-by-Okwa-and-marriage', era: 'heroic-age', eraOrdering: 1, sources: [{ kind: 'primary', reference: 'Hofmayr Die Schilluk' }], notes: 'Emerged from the river with her sister Ongwak; captured by Okwa. After the high-bride-price negotiation, became Okwa\'s wife.' },
        { typeStatus: 'deity', startEvent: 'motherhood-of-Nyikang-and-Duwat', era: 'heroic-age', eraOrdering: 2, sources: [{ kind: 'primary', reference: 'Hofmayr Die Schilluk' }], notes: 'Bore the twin demigods Nyikang and Duwat to Okwa — the divine-mother in the strict-criterion-demigod calculation for the founders of the Shilluk Kingdom.' },
      ],
      domains: [
        { sphereId: 'crocodile-river-goddess-of-the-Nile-and-Sobat', contextTag: 'lifelong', sources: [{ kind: 'primary', reference: 'Hofmayr; Seligman' }] },
        { sphereId: 'maternal-ancestor-of-the-Shilluk-Kingdom', contextTag: 'lifelong', sources: [{ kind: 'primary', reference: 'Shilluk royal-genealogical tradition' }], notes: 'Special annual sacrifices were made at the start of the rainy season in her honor as the most important spiritual force after Juok (the creator-god) himself.' },
      ],
