      lifecycle: [
        { typeStatus: 'mortal', startEvent: 'existence-as-Alban-noble-companion-of-Romulus', era: 'regal', eraOrdering: 0, sources: [{ kind: 'primary', reference: 'Liv. 1.16.5-8; Cic. Rep. 2.20; Ov. Fast. 2.499-509; Plut. Rom. 28.1-3' }], notes: 'Alban noble (some traditions ascribe him to the gens Iulia in early-republican-period genealogical-claim) who served as Romulus\' companion during the regal period.' },
        { typeStatus: 'mortal', startEvent: 'witness-of-Romulus-apotheosis-on-the-Via-Appia', era: 'regal', eraOrdering: 1, sources: [{ kind: 'primary', reference: 'Liv. 1.16.5-8; Cic. Rep. 2.20; Ov. Fast. 2.499-509; Plut. Rom. 28.1-3' }], notes: 'Following Romulus\' disappearance during a sudden storm at the Caprae Palus, Iulius Proculus came forward to swear before the assembled people that he had encountered the deified Romulus on the Via Appia. The apotheosed Romulus, now divine and surpassingly tall and beautiful, instructed Proculus to tell the Romans to worship him as Quirinus and to make Rome the head of the world by cultivating military discipline. The Iulius-Proculus testimony is the canonical Roman foundation of the cult of Quirinus and the conventional anchor for the apotheosis-of-the-founder political-religious template that persisted through the imperial-period deifications of Julius Caesar, Augustus, and subsequent principes.' },
      ],
