      temporal: {
        era: 'akkadian-empire',
        mythicStart: -2285,  // Sargon's daughter; high priestess of Nanna at Ur; world's earliest named author
        mythicEnd: -2250,
        // textualStart/End inherit from ERA_DATES['Mesopotamian']['akkadian-empire'] defaults
        mythicPrecision: 'specific',
      },
      lifecycle: [
        { typeStatus: 'mortal', startEvent: 'birth-as-Sargon-daughter', era: 'akkadian-empire', eraOrdering: 0, sources: [{ kind: 'primary', reference: 'Disk of Enheduanna (UPenn CBS 16665) — her own self-identification as Sargon\'s daughter; Sumerian Temple Hymns colophon' }], notes: 'Daughter of Sargon of Akkad; the relationship is canonically attested in her own self-authored colophons and the Disk of Enheduanna inscription.' },
        { typeStatus: 'mortal', vitalStatus: 'en-priestess-of-Nanna-at-Ur', era: 'akkadian-empire', eraOrdering: 1, startEvent: 'installation-as-en-of-Nanna-at-Ur-c-2285-bce', sources: [{ kind: 'primary', reference: 'Disk of Enheduanna (UPenn CBS 16665, the alabaster disk-relief from the Giparu at Ur depicting her installation-rite); Sargon\'s installation-decree fragments' }], notes: 'Installed by her father Sargon as the en-priestess (high-priestess) of the moon-god Nanna at Ur — the canonical-foundational appointment of the Akkadian-period royal-female-priestess office that continued for ~500 years until the end of the Ur III dynasty. The Giparu at Ur was her residence-and-cult-complex; the Disk of Enheduanna was excavated there by Leonard Woolley\'s 1928 season.' },
        { typeStatus: 'mortal', startEvent: 'composition-of-the-Sumerian-Temple-Hymns-and-Innana-cycle', era: 'akkadian-empire', eraOrdering: 2, sources: [{ kind: 'primary', reference: 'Sumerian Temple Hymns (ETCSL 4.80.1, 42 hymns to the major Sumerian temples, with colophon "the compiler of these tablets is En-ḫedu-Ana"); the three Innana hymns: nin-me-šara ("Lady of all the Me," ETCSL 4.07.2), in-nin ša-gur-ra (ETCSL 4.07.3), in-nin me-ḫuš-a (ETCSL 4.07.4)' }], notes: 'The world\'s first named author — composed the Sumerian Temple Hymns (a 42-hymn cycle to the major Sumerian temples) with explicit signature-colophon naming herself the compiler. Also composed the three great Innana hymns: nin-me-šara ("Lady of All the Me"), in-nin ša-gur-ra, and in-nin me-ḫuš-a — the most-elaborate Sumerian-literary-tradition hymns to the goddess Innana. The hymns establish Innana as the supreme goddess of the Akkadian state-cult, paralleling her father Sargon\'s political consolidation of the Mesopotamian city-states.' },
        { typeStatus: 'mortal', startEvent: 'expulsion-from-Ur-during-Lugalanne-revolt-and-restoration', era: 'akkadian-empire', eraOrdering: 3, sources: [{ kind: 'primary', reference: 'nin-me-šara hymn (ETCSL 4.07.2, lines 66-138, the canonical autobiographical-hymn passage)' }], notes: 'Per her own autobiographical hymn nin-me-šara, expelled from her position at Ur during a revolt led by the rebel-king Lugalanne — the canonical-Sumerian first-person literary-autobiography. The hymn records her appeal to Innana for restoration; the goddess answered, and Enheduanna was restored to her office. The autobiographical-first-person passage is the canonical-foundational text of the autobiographical-literary genre in human history.' },
        { typeStatus: 'mortal', startEvent: 'continuation-of-priestess-office-into-Naram-Sin-period', era: 'akkadian-empire', eraOrdering: 4, sources: [{ kind: 'primary', reference: 'Naram-Sin period seals from the Giparu' }], notes: 'Continued in office during her brothers\' reigns (Rimush, Manishtushu) and into her grand-nephew Naram-Sin\'s reign — the canonical-female-figure of cultural-religious continuity across the Akkadian dynasty\'s political turmoil.' },
        { vitalStatus: 'deceased', era: 'akkadian-empire', eraOrdering: 5, startEvent: 'death-c-2250-bce' },
      ],
      domains: [{ id: 'en-priestess-of-Nanna' }, { id: 'world-s-first-named-author' }, { id: 'Sumerian-literary-foundation' }, { id: 'Innana-cult-foundation' }],
