      lifecycle: [
        { typeStatus: 'demigod', startEvent: 'birth-as-Apollo-Antianeira-or-Cyrene-son', era: 'heroic-age', eraOrdering: 0, sources: [{ kind: 'primary', reference: 'Apoll. Rhod. Argon. 1.139-145; Hyg. Fab. 14, 248; Apollod. 1.9.16' }], notes: 'Son of Apollo by Antianeira (daughter of Menetes) per Apollonius Rhod. Argonautica 1.139-145; or by Cyrene per the variant — though Apollonius preserves the canonical-mortal-paternity-cover-story that Idmon was reputed-son of Abas the Argive. Demigod-tier through paternal Apollo-line. Inherited prophetic-faculty from his father.' },
        { typeStatus: 'demigod', startEvent: 'Argonautic-expedition-knowing-of-his-own-death', era: 'heroic-age', eraOrdering: 1, sources: [{ kind: 'primary', reference: 'Apoll. Rhod. Argon. 1.139-145, 1.443-449; Apollod. 1.9.16; Hyg. Fab. 14' }], notes: 'Joined the Argonautic expedition despite foreknowing his own death from his prophetic-faculty — the canonical-Apollonian foreknown-yet-chosen-fate paradigm of Argonautica 1.139-145: "he knew well that he was to die... yet he came not to refuse the noble repute that should be his for going." The canonical-Greek heroic-age choice-of-glory-over-life narrative-paradigm.' },
        { vitalStatus: 'deceased', era: 'heroic-age', eraOrdering: 2, startEvent: 'death-by-boar-wound-in-Mariandynian-territory', sources: [{ kind: 'primary', reference: 'Apoll. Rhod. Argon. 2.815-850; Apollod. 1.9.23; Hyg. Fab. 14, 18' }], notes: 'Killed by a boar-wound in the territory of King Lycus the Mariandynian (Pontic coast, near Heraclea Pontica) per Apollonius 2.815-850 and Apollod. 1.9.23. The Argonauts buried him on the Mariandynian shore; the city of Heraclea Pontica was canonically founded on the site of his tomb per Apollonius — a foundation-narrative tying the historical Megarian colonial-foundation of Heraclea Pontica (560 BCE) to the canonical-Argonautic Idmon-burial site.' },
      ],
